/**
 * GHL SSO Page
 * 
 * Handles authentication via GHL postMessage SSO
 * Dark theme with brand colors: #0f172a (navy), #06b6d4 (cyan accent)
 */

'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';

export default function AuthenticationHandler() {
  const router = useRouter();
  const [status, setStatus] = useState<'loading' | 'error' | 'success'>('loading');
  const [errorMessage, setErrorMessage] = useState('');

  useEffect(() => {
    const handleAuthentication = async () => {
      try {
        // Check if we're in an iframe
        if (window.self === window.top) {
          console.log('Not in iframe, redirecting to homepage');
          router.push('/');
          return;
        }

        console.log('GHL SSO: Requesting user data from parent window');
        
        // Request user data from parent window
        window.parent.postMessage({ message: 'REQUEST_USER_DATA' }, '*');

        // Listen for response
        const handleMessage = async (event: MessageEvent) => {
          console.log('GHL SSO: Received message:', event.data);

          if (event.data.message === 'RESPONSE_USER_DATA') {
            const userData = event.data.payload;
            
            if (!userData) {
              throw new Error('No user data received from GHL');
            }

            console.log('GHL SSO: User data received, processing authentication');

            // Send to our backend API to create/verify session
            const response = await fetch('/api/auth/ghl-sso', {
              method: 'POST',
              headers: {
                'Content-Type': 'application/json',
              },
              body: JSON.stringify(userData),
            });

            if (!response.ok) {
              throw new Error('Failed to authenticate with backend');
            }

            const result = await response.json();
            console.log('GHL SSO: Authentication successful:', result);

            setStatus('success');
            
            // Redirect to dashboard after successful authentication
            setTimeout(() => {
              router.push('/dashboard');
            }, 1000);
          }
        };

        window.addEventListener('message', handleMessage);

        // Timeout after 10 seconds
        setTimeout(() => {
          if (status === 'loading') {
            throw new Error('Authentication timeout - no response from GHL');
          }
        }, 10000);

        return () => {
          window.removeEventListener('message', handleMessage);
        };
      } catch (error: any) {
        console.error('GHL SSO Error:', error);
        setStatus('error');
        setErrorMessage(error.message || 'Authentication failed');
      }
    };

    handleAuthentication();
  }, [router, status]);

  return (
    <div className="min-h-screen bg-[#0f172a] flex items-center justify-center p-4">
      {/* Background gradient overlay */}
      <div className="absolute inset-0 bg-gradient-to-br from-[#06b6d4]/10 via-transparent to-[#06b6d4]/5 pointer-events-none" />
      
      <div className="w-full max-w-md relative z-10">
        {/* Glass morphism card */}
        <div className="bg-[#0f172a]/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl p-8">
          <div className="text-center">
            {status === 'loading' && (
              <>
                <div className="w-16 h-16 mx-auto mb-6 relative">
                  <div className="absolute inset-0 border-4 border-[#06b6d4]/20 rounded-full"></div>
                  <div className="absolute inset-0 border-4 border-[#06b6d4] border-t-transparent rounded-full animate-spin"></div>
                </div>
                <h2 className="text-xl font-semibold text-white mb-2">
                  Connecting to GHL
                </h2>
                <p className="text-gray-400 text-sm">
                  Please wait while we authenticate your session...
                </p>
              </>
            )}

            {status === 'success' && (
              <>
                <div className="w-16 h-16 mx-auto mb-6 bg-[#10b981]/10 rounded-full flex items-center justify-center">
                  <svg className="w-8 h-8 text-[#10b981]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                  </svg>
                </div>
                <h2 className="text-xl font-semibold text-white mb-2">
                  Authentication Successful
                </h2>
                <p className="text-gray-400 text-sm">
                  Redirecting to dashboard...
                </p>
              </>
            )}

            {status === 'error' && (
              <>
                <div className="w-16 h-16 mx-auto mb-6 bg-[#ef4444]/10 rounded-full flex items-center justify-center">
                  <svg className="w-8 h-8 text-[#ef4444]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </div>
                <h2 className="text-xl font-semibold text-white mb-2">
                  Authentication Failed
                </h2>
                <p className="text-[#ef4444] text-sm mb-6">
                  {errorMessage}
                </p>
                <button
                  onClick={() => router.push('/')}
                  className="px-6 py-2.5 bg-[#06b6d4] hover:bg-[#06b6d4]/90 text-white font-medium rounded-lg shadow-lg shadow-[#06b6d4]/30 transition-all"
                >
                  Go to Login
                </button>
              </>
            )}
          </div>
        </div>

        {/* Debug info */}
        <div className="mt-6 text-center text-xs text-gray-500">
          <p>GHL SSO Authentication Handler</p>
        </div>
      </div>
    </div>
  );
}